async function s(){const t=await chrome.storage.local.get(["accessToken"]);if(t.accessToken)return t.accessToken;try{const e=await(await fetch("http://localhost:3000/auth/guest",{method:"POST"})).json();if(e.guestToken)return await chrome.storage.local.set({accessToken:e.guestToken}),e.guestToken}catch(a){console.error("Failed to get guest token",a)}return""}async function o(t){if(!t)return!0;try{const e=await(await fetch("http://localhost:3000/usage",{headers:{Authorization:`Bearer ${t}`}})).json();return e.remaining>0||e.plan!=="FREE"}catch(a){return console.error("Usage check failed",a),!0}}export{o as c,s as g};
